fill((1,0)--(3,2)--(3,3)--(2,3)--(0,1)--cycle,gray(.7));
draw((1,-.1)--(1,.1));
draw((2,-.1)--(2,.1));
draw((.1,1)--(-.1,1));
draw((.1,2)--(-.1,2));

draw((1,0)--(0,1));
draw((1,0)--(3,2));
